{
  "name": "fibonacci",
  "description": "Hitung angka Fibonacci ke-n. Parameter: n (int) — posisi dalam deret Fibonacci (mulai dari 0). Contoh: fibonacci(10) = 55",
  "code": "def fibonacci(n: int) -> int:
    """Hitung angka Fibonacci ke-n secara iteratif."""
    if n < 0:
        raise ValueError(f'n harus >= 0, dapat: {n}')
    if n <= 1:
        return n
    a, b = 0, 1
    for _ in range(2, n + 1):
        a, b = b, a + b
    return b"
}

{
  "name": "convert_temperature",
  "description": "Konversi suhu antar satuan. Parameter: value (float) — nilai suhu, from_unit (str) — satuan asal ('celsius'/'fahrenheit'/'kelvin'), to_unit (str) — satuan tujuan.",
  "code": "def convert_temperature(value: float, from_unit: str, to_unit: str) -> float:
    """Konversi suhu antar satuan celsius, fahrenheit, kelvin."""
    from_unit = from_unit.lower()
    to_unit = to_unit.lower()
    # Konversi ke Celsius dulu
    if from_unit == 'fahrenheit':
        celsius = (value - 32) * 5 / 9
    elif from_unit == 'kelvin':
        celsius = value - 273.15
    elif from_unit == 'celsius':
        celsius = value
    else:
        raise ValueError(f'Satuan tidak dikenal: {from_unit}')
    # Konversi dari Celsius ke target
    if to_unit == 'fahrenheit':
        return celsius * 9 / 5 + 32
    elif to_unit == 'kelvin':
        return celsius + 273.15
    elif to_unit == 'celsius':
        return celsius
    else:
        raise ValueError(f'Satuan tidak dikenal: {to_unit}')"
}

